318→const CAT_NAMES = { labor:"劳动法", commercial:"商法", economic:"经济法", civil:"民事实体", procedure:"诉讼程序" };
319→const DUR_NAMES = { short:"≤15日", medium:"1-6个月", long:"1-3年", vlong:"3年以上" };
320→
321→let curCat = "all", curDur = "all", curSearch = "";
322→
323→function render() {
324→    const filtered = DATA.filter(d => {
325→        if (curCat === "warning") { if (!d.warn) return false; }
326→        else if (curCat !== "all" && d.cat !== curCat) return false;
327→        if (curDur !== "all" && d.dur !== curDur) return false;
328→        if (curSearch) {
329→            const s = curSearch.toLowerCase();
330→            const t = (d.name + d.time + d.desc + d.risk + d.law).toLowerCase();
331→            if (!t.includes(s)) return false;
332→        }
333→        return true;
334→    });
335→
336→    // 统计
337→    const total = filtered.length;
338→    const warnCount = filtered.filter(d => d.warn).length;
339→    const catCount = new Set(filtered.map(d => d.cat)).size;
340→    document.getElementById('stats').innerHTML = `
341→        <div class="stat-card"><div class="num">${total}</div><div class="label">匹配条目</div></div>
342→        <div class="stat-card warn"><div class="num">${warnCount}</div><div class="label">高风险项</div></div>
343→        <div class="stat-card"><div class="num">${catCount}</div><div class="label">涉及门类</div></div>
344→    `;
345→
346→    // 卡片
347→    const list = document.getElementById('cardList');
348→    const noRes = document.getElementById('noResult');
349→    if (!filtered.length) { list.innerHTML = ''; noRes.style.display = 'block'; return; }
350→    noRes.style.display = 'none';
351→
352→    list.innerHTML = filtered.map((d, i) => `
353→        <div class="card cat-${d.cat} ${d.warn ? 'warn-card' : ''}" onclick="this.classList.toggle('expanded')">
354→            ${d.warn ? '<div class="warn-badge">⚠ 高风险</div>' : ''}
355→            <div class="cat-tag">${CAT_NAMES[d.cat]}</div>
356→            <div class="title">${highlight(d.name)}</div>
357→            <div class="duration">${highlight(d.time)}</div>
358→            <div class="desc">${highlight(truncate(d.desc, 80))}</div>
359→            <div class="detail">
360→                <div class="desc" style="margin-bottom:10px">${highlight(d.desc)}</div>
361→                <div class="risk">${highlight(d.risk)}</div>
362→                <div class="law-ref">📖 ${highlight(d.law)}</div>
363→            </div>
364→            <div class="expand-hint">点击展开/收起详情 ▾</div>
365→        </div>
366→    `).join('');
367→}
368→
369→function truncate(s, n) { return s.length > n ? s.slice(0, n) + '...' : s; }
370→
371→function highlight(text) {
372→    if (!curSearch) return text;
373→    const re = new RegExp('(' + curSearch.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi');
374→    return text.replace(re, '<mark style="background:#fbbf24;color:#0f172a;border-radius:2px;padding:0 2px">$1</mark>');
375→}
